function ImageGen() {
  const [prompt, setPrompt] = React.useState('A serene mountain lake at sunset with reflections');
  const [generating, setGenerating] = React.useState(false);
  const [result, setResult] = React.useState(null);
  const [history, setHistory] = React.useState([
    { prompt: 'A futuristic city skyline at night', status: 'done' },
    { prompt: 'A cozy cabin in snowy woods', status: 'done' }
  ]);

  function generate() {
    if (!prompt.trim()) return;
    setGenerating(true);
    setResult(null);
    setTimeout(() => {
      setResult({ prompt, seed: Math.floor(Math.random() * 1000000) });
      setHistory([{ prompt, status: 'done' }, ...history]);
      setGenerating(false);
    }, 1500);
  }

  const placeholders = [
    'A cat astronaut in space',
    'Vintage car on a coastal road',
    'Abstract geometric pattern',
    'Mystical forest with glowing mushrooms'
  ];

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Image Generator</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        <textarea
          value={prompt}
          onChange={e => setPrompt(e.target.value)}
          style={{ flex: 1, height: 50, padding: 10, borderRadius: 6, border: '1px solid #ddd', fontSize: 13, resize: 'none', boxSizing: 'border-box' }}
          placeholder="Describe the image you want to generate..."
        />
        <button
          onClick={generate}
          disabled={generating}
          style={{ padding: '0 18px', borderRadius: 6, border: 'none', background: generating ? '#9ca3af' : '#7c3aed', color: '#fff', fontSize: 13, cursor: generating ? 'not-allowed' : 'pointer' }}
        >
          {generating ? '...' : 'Generate'}
        </button>
      </div>
      <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginBottom: 12 }}>
        {placeholders.map((p, i) => (
          <button
            key={i}
            onClick={() => setPrompt(p)}
            style={{ padding: '4px 10px', borderRadius: 12, border: '1px solid #ddd', background: '#f3f4f6', fontSize: 11, cursor: 'pointer', color: '#374151' }}
          >
            {p.length > 25 ? p.slice(0, 25) + '...' : p}
          </button>
        ))}
      </div>
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 10, overflow: 'hidden' }}>
        <div style={{ flex: 1, borderRadius: 8, background: '#f3f4f6', border: '1px solid #e5e7eb', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', position: 'relative' }}>
          {generating ? (
            <div style={{ textAlign: 'center', color: '#6b7280' }}>
              <div style={{ width: 32, height: 32, border: '3px solid #e5e7eb', borderTopColor: '#7c3aed', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 8px' }} />
              <div style={{ fontSize: 13 }}>Generating image...</div>
            </div>
          ) : result ? (
            <div style={{ textAlign: 'center', padding: 20 }}>
              <div style={{ width: 120, height: 120, borderRadius: 12, background: 'linear-gradient(135deg, #c4b5fd 0%, #a78bfa 100%)', margin: '0 auto 12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 48 }}>\ud83c\udfa8</div>
              <div style={{ fontSize: 12, color: '#6b7280', maxWidth: 260, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{result.prompt}</div>
              <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 4 }}>Seed: {result.seed}</div>
            </div>
          ) : (
            <div style={{ color: '#9ca3af', fontSize: 13, textAlign: 'center' }}>Your generated image will appear here</div>
          )}
        </div>
        <div style={{ maxHeight: 100, overflowY: 'auto' }}>
          <div style={{ fontSize: 11, color: '#9ca3af', marginBottom: 4 }}>Recent</div>
          {history.map((h, i) => (
            <div
              key={i}
              onClick={() => setPrompt(h.prompt)}
              style={{ padding: '6px 10px', borderRadius: 6, background: '#f9fafb', marginBottom: 4, fontSize: 12, color: '#4b5563', cursor: 'pointer', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
            >
              {h.prompt}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
render(<ImageGen/>);
